<template>
	<view class="page">
		<template v-if="token">
			<u-navbar :z-index="980" :is-back="true" :custom-back="pageBack">
				<template #default>
					<view class="header">
						<view class="title"><text>购物车</text>({{goodsNum}})</view>
						<view class="express" @click="() => {
							$util.on('/pages/ucenter_sub/express/index')
						}">
							<template v-if="express.address">
								<text class="line1">{{express.address}}</text>
								<u-icon name="arrow-right" color="#e0e0e0" size="20"></u-icon>
							</template>
							<template v-else>
								<text style="color: red;">暂无收货地址!</text>
							</template>
						</view>
						<view class="btns">
							<view class="btn-item" @click="handelManager">
								<template v-if="isManage">
									取消管理
								</template>
								<template v-else>
									管理
								</template>
							</view>
						</view>
					</view>

				</template>
			</u-navbar>
			<view class="goods-box">
				<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:scrollHeight+'px'}"
					:rebound="false">
					<goods-list ref="goods-list" :goodsList="goodsList" :selectedIds="selectedIds" :is-manage="isManage"
						@selected-ids="handelSelectedIdsChange" @spec-choose="handelSpecChoose"
						@ordertpl-choose="handelOrderTplChoose">
						<template v-slot:quantity="{row,idx}">
							<goods-num :quantity="row.num" :num-type="row.goods.num_type"
								:start-count="row.goods.start_count" :end-count="row.goods.end_count"
								:num-count="row.goods.num_count" @quantity-change="handelQuantityChange(row,$event)" />
						</template>
					</goods-list>
				</scroll-view>
			</view>
			<view class="footer">
				<view class="wrap">
					<view class="checker" :class="{'checker-on':isSelectAll}" @click="handelAllSelected">
						<u-icon name="checkmark-circle"></u-icon>
						<text>全选</text>
					</view>
					<view class="right">
						<template v-if="isManage">
							<view class="settle-btn" @click="handelDelete">删除</view>
						</template>
						<template v-else>
							<view class="total">
								合计：<text>¥</text><text>{{amountPrice}}</text>
							</view>
							<view class="settle-btn" @click="handelSettle">结算</view>
						</template>
					</view>
				</view>
			</view>
		</template>
		<template v-else>
			<view class="cart-empty">
				<view class="wrap">
					<u-icon name="shopping-cart" color="#F05C02" size="100"></u-icon>
					<view class="right">
						<text class="title">登录后将显示您之前加入的商品</text>
						<view>
							<u-button size="mini" @click="() => {
								$Router.push({
									path:'/pages/user/login',
									query:{
										redirect:'/pages/cart/index'
									}
								})
							}">登录</u-button>
						</view>
					</view>
				</view>
			</view>
		</template>

		<u-tabbar :height="110" active-color='#f06c7a' inactive-color="#606266" :list="tabBarList"></u-tabbar>
		<spec-choose ref="spec-choose" @ok="handelSpecChange" :custom-style="{'margin-bottom':'100rpx'}" />
		<ordertpl-choose ref="ordertpl-choose" @ok="handelOrderTplChange" :custom-style="{'margin-bottom':'100rpx'}" />
	</view>
</template>

<script>
	import GoodsList from './components/goods-list'
	import ChooseGoodsSpecDialog from '@/components/ChooseGoodsSpecDialog/'
	import ChooseOrderTplDialog from '@/components/ChooseOrderTplDialog/'
	import GoodsNum from './components/goods-num'
	import {
		mapGetters
	} from 'vuex'

	export default {
		components: {
			'goods-list': GoodsList,
			'spec-choose': ChooseGoodsSpecDialog,
			'ordertpl-choose': ChooseOrderTplDialog,
			'goods-num': GoodsNum
		},
		data() {
			return {
				scrollHeight: 0,

				express: {},
				goodsList: [],

				isManage: false,

				isSelectAll: false,
				selectedIds: [], //唯一id,目前使用的购物车id,与商品id是一对多的关系（可能是多规格）

				orderForm: {
					address_id: '', //收货地址id
					cart_batch_tpl: [], //购物车下单数据
					// 暂定，缺少快递，
				}, //购物车下单
			}
		},
		watch: {

		},
		computed: {
			...mapGetters(['deviceInfo']),
			goodsNum() {
				if (this.goodsList.length) {
					let i = 0
					this.goodsList.map(item => {
						if (item.list && Array.isArray(item.list)) {
							i += item.list.length
						}
					})
					return i
				} else
					return 0
			},
			amountPrice() {
				if (this.goodsList.length) {
					let i = 0
					this.goodsList.map(item => {
						if (item.list && Array.isArray(item.list)) {
							item.list.map(item2 => {
								let index = this.selectedIds.findIndex(id => id == item2.id)
								if (index != -1) {
									if (item2.attr) {
										i = this.$util.bcadd(i, this.$util.bcmul(item2.attr.goods_price,
											item2
											.num))
									} else {
										i = this.$util.bcadd(i, this.$util.bcmul(item2.goods.goods_price,
											item2
											.num))
									}
								}
							})
						}
					})
					return i
				} else
					return 0
			},
		},
		onReady() {

		},
		onLoad() {

		},
		onShow() {
			// console.log(this.token);
			if (this.token) {
				this.$nextTick(() => {
					uni.createSelectorQuery().in(this).select(".scroll_content").boundingClientRect(res => {
						this.scrollHeight = this.deviceInfo.screenHeight - res.top - uni.upx2px(110) - uni
							.upx2px(100)
					}).exec()
				})
				this.loadExpressData()
				this.loadData()
			}
		},
		onHide() {
			this.isManage = false
			this.isSelectAll = false
			this.selectedIds = []
		},
		methods: {
			pageBack() {
				this.$util.back()
			},
			async loadExpressData() {
				const data = await this.$u.api.readMemberAddress()
				this.express = Object.assign({}, data)
				this.orderForm.address_id = this.express.id
			},
			async loadData() {
				const data = await this.$u.api.goodsCart()
				this.goodsList = data
			},
			// 管理点击
			handelManager() {
				this.isManage = !this.isManage
				this.isSelectAll = false
				this.selectedIds = []
			},
			// 删除点击
			handelDelete() {
				if (!this.selectedIds.length) {
					this.$util.msg('请选择商品')
					return
				}
				this.$u.throttle(async () => {
					await this.$u.api.goodsCartDelete({
						ids: [...this.selectedIds]
					})
					this.loadData()
				}, 500)
			},
			// 全选点击
			handelAllSelected() {
				this.isSelectAll = !this.isSelectAll
				if (this.isSelectAll) {
					let ids = []
					this.goodsList.map(item => {
						if (item.list && Array.isArray(item.list)) {
							item.list.map(item2 => {
								ids.push(item2.id)
							})
						}
					})
					this.selectedIds = ids
				} else {
					this.selectedIds = []
				}
			},
			// 选中商品改变回调
			handelSelectedIdsChange({
				selectedIds,
				isSelectAll
			}) {
				this.selectedIds = selectedIds
				this.isSelectAll = isSelectAll
			},
			// 显示规格选择
			handelSpecChoose(e) {
				this.$refs['spec-choose'].show(e)
			},
			// 选择规格回调
			async handelSpecChange(e) {
				await this.$u.api.goodsCartSave(e.editForm)
				this.loadData()
			},
			// 显示下单模板
			handelOrderTplChoose(e) {
				this.$refs['ordertpl-choose'].showEdit(e)
			},
			// 选择下单模板回调
			handelOrderTplChange({
				id,
				goods_id,
				batch_tpl,
				mark
			}) {
				this.$u.api.goodsCartSave({
					id,
					goods_id,
					batch_tpl: JSON.stringify(batch_tpl),
					mark
				})
			},
			// 商品数量回调
			handelQuantityChange(row, num) {
				row.num = num
				this.$u.api.goodsCartNum({
					id: row.id,
					num
				})
			},
			// 结算点击
			handelSettle() {
				if (!this.selectedIds.length) {
					this.$util.msg('请选择商品')
					return
				}

				this.$util.on(`/pages/goods/create_order?cart_ids=${this.selectedIds.join(',')}`)
			},
		}
	}
</script>
<style lang="scss" scoped scoped>
	.page {
		background-color: rgb(250, 250, 250);
		position: relative;
		min-height: 100vh;
	}

	.checker {
		color: #B0B0B0 !important;
	}

	.checker-on {
		color: #F05C02 !important;
	}

	.header {
		display: flex;
		align-items: center;
		justify-content: space-evenly;
		height: 100%;
		flex: 1;
		// padding: 0 20rpx;


		.title {
			&>text:nth-child(1) {
				font-size: 30rpx;
				font-weight: bold;
			}
		}

		.express {
			flex: 1;
			text-align: center;
			display: flex;
			align-items: center;
			justify-content: center;
			gap: 10rpx;
			overflow: hidden;
		}

		.btns {
			display: flex;
			justify-content: flex-end;
			width: 140rpx;
			padding-right: 20rpx;

			.btn-item {}
		}
	}

	.goods-box {
		margin-top: 20rpx;
	}

	.footer {
		position: fixed;
		bottom: 110rpx;
		z-index: 11;
		width: 100%;
		height: 100rpx;
		background-color: #fff;
		flex-wrap: nowrap;
		justify-content: space-between;
		align-items: center;
		display: flex;
		padding: 0 20rpx;

		.wrap {
			width: 100%;
			display: flex;
			align-items: center;
			justify-content: space-between;

			.checker {
				&>text:nth-child(2) {
					margin-left: 10rpx;
				}
			}

			.right {
				display: flex;
				align-items: center;
				gap: 20rpx;

				.total {
					&>text:nth-child(1) {
						font-size: 20rpx;
						color: #F05C02;
					}

					&>text:nth-child(2) {
						font-size: 40rpx;
						color: #F05C02;
					}
				}

				.settle-btn {
					display: flex;
					align-items: center;
					justify-content: center;
					background-color: #F05C02;
					border-radius: 30rpx;
					color: #fff;
					width: 200rpx;
					padding: 10rpx 0;
				}
			}
		}
	}

	.cart-empty {
		position: absolute;
		top: 50%;
		left: 50%;
		transform: translate(-50%, -50%);

		.wrap {
			display: flex;
			gap: 20rpx;

			.right {
				display: flex;
				flex-direction: column;
				gap: 20rpx;
				width: 400rpx;
			}
		}
	}
</style>