<template>
	<view class="uni-data-pickerview">
		<!-- 全部新增，上面哪个搜索框 -->
		<view style="padding: 20rpx;display: flex;" v-if="hasSearch === true">
			<u-search placeholder="请输入搜索内容" v-model="searchValue" @change="handleInput" :show-action="false"></u-search>
		</view>

		<view class="uni-data-pickerview" style="margin-bottom: 0;" v-if="!searchContent">
			<scroll-view v-if="!isCloudDataList" class="selected-area" scroll-x="true">
				<view class="selected-list">
					<view class="selected-item" v-for="(item,index) in selected" :key="index" :class="{
			      'selected-item-active':index == selectedIndex
			    }" @click="handleSelect(index)">
						<text>{{item.text || ''}}</text>
					</view>
				</view>
			</scroll-view>
			<view class="tab-c">
				<scroll-view class="list" :scroll-y="true">
					<view class="item" :class="{'is-disabled': !!item.disable}"
						v-for="(item, j) in dataList[selectedIndex]" :key="j"
						@click="handleNodeClick(item, selectedIndex, j)">
						<text class="item-text">{{item[map.text]}}</text>
						<view class="check"
							v-if="selected.length > selectedIndex && item[map.value] == selected[selectedIndex].value">
						</view>
					</view>
				</scroll-view>

				<view class="loading-cover" v-if="loading">
					<uni-load-more class="load-more" :contentText="loadMore" status="loading"></uni-load-more>
				</view>
				<view class="error-message" v-if="errorMessage">
					<text class="error-text">{{errorMessage}}</text>
				</view>
			</view>
		</view>
		<!-- 搜索结果-列表 -->
		<view class="uni-data-pickerview" style="overflow: auto; margin-bottom: 0;" v-else>
			<view class="result-list">
				<view v-for="(item,index) of searchList" :key="index" class="result-item">
					<view class="path-wrap" @click="chooseItem(item)">
						<view class="path-item" v-for="path_item,path_index in item.path" :key="path_index"
							v-html="path_item._label_html"></view>
					</view>
				</view>
				<view class="no-data" v-if="!searchList.length">未找到符合的数据！</view>
			</view>
		</view>
	</view>
</template>

<script>
	import dataPicker from "./uni-data-picker.js"
	import _ from 'lodash'

	/**
	 * DataPickerview
	 * @description uni-data-pickerview
	 * @tutorial https://ext.dcloud.net.cn/plugin?id=3796
	 * @property {Array} localdata 本地数据，参考
	 * @property {Boolean} step-searh = [true|false] 是否分布查询
	 * @value true 启用分布查询，仅查询当前选中节点
	 * @value false 关闭分布查询，一次查询出所有数据
	 * @property {String|DBFieldString} self-field 分布查询当前字段名称
	 * @property {String|DBFieldString} parent-field 分布查询父字段名称
	 * @property {String|DBCollectionString} collection 表名
	 * @property {String|DBFieldString} field 查询字段，多个字段用 `,` 分割
	 * @property {String} orderby 排序字段及正序倒叙设置
	 * @property {String|JQLString} where 查询条件
	 */
	export default {
		name: 'UniDataPickerView',
		emits: ['nodeclick', 'change', 'datachange', 'update:modelValue'],
		mixins: [dataPicker],
		props: {
			managedMode: {
				type: Boolean,
				default: false
			},
			ellipsis: {
				type: Boolean,
				default: true
			},
			hasSearch: {
				type: Boolean,
				default: false,
			}
		},
		data() {
			return {
				// 搜索字段
				searchValue: '',
				searchContent: false, //显示搜索结果
				searchList: [] //搜索出来的列表（数组）
			}
		},
		created() {
			if (!this.managedMode) {
				this.$nextTick(() => {
					this.loadData();
				})
			}
		},
		methods: {
			onPropsChange() {
				this._treeData = [];
				this.selectedIndex = 0;
				this.$nextTick(() => {
					this.loadData();
				})
			},
			handleSelect(index) {
				this.selectedIndex = index;
			},
			handleNodeClick(item, i, j) {
				if (item.disable) {
					return;
				}

				const node = this.dataList[i][j];
				const text = node[this.map.text];
				const value = node[this.map.value];

				if (i < this.selected.length - 1) {
					this.selected.splice(i, this.selected.length - i)
					this.selected.push({
						text,
						value
					})
				} else if (i === this.selected.length - 1) {
					this.selected.splice(i, 1, {
						text,
						value
					})
				}

				if (node.isleaf) {
					this.onSelectedChange(node, node.isleaf)
					return
				}

				const {
					isleaf,
					hasNodes
				} = this._updateBindData()

				// 本地数据
				if (this.isLocalData) {
					this.onSelectedChange(node, (!hasNodes || isleaf))
				} else if (this.isCloudDataList) { // Cloud 数据 (单列)
					this.onSelectedChange(node, true)
				} else if (this.isCloudDataTree) { // Cloud 数据 (树形)
					if (isleaf) {
						this.onSelectedChange(node, node.isleaf)
					} else if (!hasNodes) { // 请求一次服务器以确定是否为叶子节点
						this.loadCloudDataNode((data) => {
							if (!data.length) {
								node.isleaf = true
							} else {
								this._treeData.push(...data)
								this._updateBindData(node)
							}
							this.onSelectedChange(node, node.isleaf)
						})
					}
				}
			},
			updateData(data) {
				this._treeData = data.treeData
				this.selected = data.selected
				if (!this._treeData.length) {
					this.loadData()
				} else {
					//this.selected = data.selected
					this._updateBindData()
				}
			},
			onDataChange() {
				this.$emit('datachange');
			},
			onSelectedChange(node, isleaf) {
				if (isleaf) {
					this._dispatchEvent()
				}

				if (node) {
					this.$emit('nodeclick', node)
				}
			},
			_dispatchEvent() {
				this.$emit('change', this.selected.slice(0))
			},
			// 牛逼算法
			// 函数来获取最后一层且名称匹配的所有节点及其路径
			// 输出最后一层名称包含 '节点1' 的节点及其路径
			searchLastLevelNodesByName(tree, name) {
				const results = [];

				function traverse(node, path = []) {
					if (node.label.includes(name) && (!node.children || node.children.length === 0)) {
						results.push({
							node,
							path: [...path, node]
						});
					} else if (node.children && node.children.length > 0) {
						node.children.forEach(child => traverse(child, [...path, node]));
					}
				}

				tree.forEach(node => traverse(node));

				return results;
			},
			createHtmlStr(str, find, tag = "text", style = "color: red;") {
				if (!str)
					return ''
				return str.replaceAll(find, `<${tag} style="${style}">${find}</${tag}>`)
			},
			handleInput: _.debounce(function(e) {
				const keyword = e
				// 如果有值，就让搜索内容展示
				if (keyword) {
					// 打开搜索 关闭原生展示
					this.searchContent = true
					// console.log('this.localdata', this.localdata)
					// 重置展示列表
					this.searchList = []
					const result = this.searchLastLevelNodesByName(this.localdata, keyword)
					if (result) {
						this.searchList = result.map(item => {
							const {
								node,
								path
							} = item
							path.forEach((path_item, path_index) => {
								if (path_index == (path.length - 1)) {
									path_item._label_html = this.createHtmlStr(path_item.label,
										keyword)
								} else {
									path_item._label_html = path_item.label
								}
							})

							return item
						})
					}
				} else {
					// 如果没有搜索词，那么就回到原始的展示
					this.searchContent = false
				}
			}, 500),
			// 点击搜索选项后调用的函数
			chooseItem(e) {
				const {
					node,
					path
				} = e
				let reinit = path.map(item => {
					return {
						text: item.label,
						value: item._random
					}
				})
				this.$emit('change', reinit)
				this.searchContent = false
			},
		}
	}
</script>

<style lang="scss" scoped>
	$uni-primary: #007aff !default;

	.uni-data-pickerview {
		flex: 1;
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		flex-direction: column;
		overflow: hidden;
		height: 100%;
	}

	.error-text {
		color: #DD524D;
	}

	.loading-cover {
		position: absolute;
		left: 0;
		top: 0;
		right: 0;
		bottom: 0;
		background-color: rgba(255, 255, 255, .5);
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		flex-direction: column;
		align-items: center;
		z-index: 1001;
	}

	.load-more {
		/* #ifndef APP-NVUE */
		margin: auto;
		/* #endif */
	}

	.error-message {
		background-color: #fff;
		position: absolute;
		left: 0;
		top: 0;
		right: 0;
		bottom: 0;
		padding: 15px;
		opacity: .9;
		z-index: 102;
	}

	/* #ifdef APP-NVUE */
	.selected-area {
		width: 750rpx;
	}

	/* #endif */

	.selected-list {
		/* #ifndef APP-NVUE */
		display: flex;
		flex-wrap: nowrap;
		/* #endif */
		flex-direction: row;
		padding: 0 5px;
		border-bottom: 1px solid #f8f8f8;
	}

	.selected-item {
		margin-left: 10px;
		margin-right: 10px;
		padding: 12px 0;
		text-align: center;
		/* #ifndef APP-NVUE */
		white-space: nowrap;
		/* #endif */
	}

	.selected-item-text-overflow {
		width: 168px;
		/* fix nvue */
		overflow: hidden;
		/* #ifndef APP-NVUE */
		width: 6em;
		white-space: nowrap;
		text-overflow: ellipsis;
		-o-text-overflow: ellipsis;
		/* #endif */
	}

	.selected-item-active {
		border-bottom: 2px solid $uni-primary;
	}

	.selected-item-text {
		color: $uni-primary;
	}

	.tab-c {
		position: relative;
		flex: 1;
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		flex-direction: row;
		overflow: hidden;
	}

	.list {
		flex: 1;
	}

	.item {
		padding: 12px 15px;
		/* border-bottom: 1px solid #f0f0f0; */
		/* #ifndef APP-NVUE */
		display: flex;
		/* #endif */
		flex-direction: row;
		justify-content: space-between;
	}

	.is-disabled {
		opacity: .5;
	}

	.item-text {
		/* flex: 1; */
		color: #333333;
	}

	.item-text-overflow {
		width: 280px;
		/* fix nvue */
		overflow: hidden;
		/* #ifndef APP-NVUE */
		width: 20em;
		white-space: nowrap;
		text-overflow: ellipsis;
		-o-text-overflow: ellipsis;
		/* #endif */
	}

	.check {
		margin-right: 5px;
		border: 2px solid $uni-primary;
		border-left: 0;
		border-top: 0;
		height: 12px;
		width: 6px;
		transform-origin: center;
		/* #ifndef APP-NVUE */
		transition: all 0.3s;
		/* #endif */
		transform: rotate(45deg);
	}

	.result-list {
		.result-item {
			padding: 20rpx 20rpx;
			margin: 0 20rpx;
			border-bottom: 1rpx solid #e5e5e5;

			&:last-child {
				border-bottom: 0;
			}

			.path-wrap {
				display: flex;
				align-items: center;
				flex-wrap: nowrap;
				gap: 20rpx;

				.path-item {
					position: relative;
					min-width: 60rpx;

					&+.path-item {
						margin-left: 10rpx;
					}

					&::after {
						position: absolute;
						content: '/';
						right: -20rpx;
					}

					&:last-child {
						&::after {
							content: '';
						}
					}
				}
			}
		}

		.no-data {
			width: 100%;
			text-align: center;
			padding: 10rpx 0;
		}
	}
</style>