<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true"
			@close="close">
			<view class="popup-title">规格选择</view>
			<view class="popup-content">
				<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:'600rpx'}">
					<goods-spec :spec-key="goodsSpecKey" :spec-value="goodsSpecValue"
						:selected-spec-value="selectedSpecValue" @change="changeSpec" />
				</scroll-view>
			</view>
			<view class="popup-footer">
				<u-button type="warning" shape="circle" @click="handelOk">确 定</u-button>
			</view>
		</u-popup>
	</view>
</template>

<script>
	import Spec from './spec.vue'
	export default {
		components: {
			'goods-spec': Spec,
		},
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			}
		},
		data() {
			return {
				popupShow: false,

				// 商品详情请求数据
				queryForm: {
					id: '',
					spec_id: '',
				},
				goods: {},
				goodsSpecKey: [], // 商品规格key,规格键列表
				goodsSpecValue: {}, //商品规格value，以规格key组合为键的对象
				selectedSpecValue: {}, //选中规格商品

				// 修改表单
				editForm: {
					id: '', //购物车id
					goods_id: '',
					goods_sku_id: '', //商品规格id
				},
			};
		},
		computed: {

		},
		watch: {

		},
		created() {

		},
		mounted() {
			
		},
		methods: {
			show({
				id,//购物车id
				goods_id,//商品id
				spec_id//商品规格id
			}) {
				this.queryForm.id = goods_id
				this.queryForm.spec_id = spec_id

				this.editForm.id = id
				this.editForm.goods_id = goods_id
				this.editForm.goods_sku_id = spec_id
				this.popupShow = true
				this.loadData()
			},
			async loadData() {
				const {
					goods,
					goods_spec_key,
					goods_spec_value,
				} = await this.$u.api.categoods(this.queryForm)
				this.goods = goods
				this.goodsSpecKey = goods_spec_key
				this.goodsSpecValue = goods_spec_value
				this.getSelectedSpecValue()
			},
			getSelectedSpecValue() {
				if (this.queryForm.spec_id) {
					for (let i in this.goodsSpecValue) {
						if (this.goodsSpecValue[i].id == this.queryForm.spec_id) {
							this.selectedSpecValue = this.goodsSpecValue[i]
							break
						}
					}
				}
			},
			close() {
				this.queryForm = this.$options.data().queryForm
				this.editForm = this.$options.data().editForm
				this.popupShow = false
			},
			// 规格改变回调
			changeSpec(e) {
				this.selectedSpecValue = e
				if (e.id) {
					this.editForm.goods_sku_id = e.id
				}
				const {
					stock_num,
					goods_img,
					face_value,
					goods_price,
				} = e
				this.goods.goods_img = goods_img
				this.goods.goods_price = goods_price
				this.goods.stock_num = stock_num
				this.goods.face_value = face_value
				//当前规格默认等价格 fonnie分享价格不是规格的价格（未完成）
				
				
			},
			handelOk() {
				this.$emit('ok', {editForm:this.editForm,specValue:this.selectedSpecValue})
				this.close()				
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.popup-content {
		padding: 20rpx;
		min-height: 600rpx;

		.wrap {
			font-size: 24rpx;
			background-color: #f4f4f5;
			height: 300rpx;
			overflow-y: auto;
		}
	}

	.popup-footer {
		padding: 40rpx;
	}
</style>