<template>
	<view style="flex: 1;">
		<!-- {{attach}} -->
		<u-form :model="tplForm" ref="uForm" label-position="top" :error-type="['message','toast']"
			v-if="!showBatchOrder">
			<u-form-item :prop="item.key" v-for="item,idx in attach" :key="idx"
				:label="item.type=='cascader'?'':item.name" :label-width="item.type=='cascader'?'0':'90'"
				:border-bottom="item.type=='cascader'?false:true">
				<template v-if="item.type=='recharge_account'">
					<u-input type="text" v-model="tplForm[item.key]" :placeholder="item.tip" />
				</template>
				<template v-else-if="item.type=='text'">
					<mix-input v-model="tplForm[item.key]" :options="item.options" :tip="item.tip" />
				</template>
				<template v-else-if="item.type=='password'">
					<u-input type="password" v-model="tplForm[item.key]" :placeholder="item.tip" />
				</template>
				<template v-else-if="item.type=='select'">
					<view @click="showSel=true" style="width: 100%;color:#999">
						{{tplForm[item.key] || '请选择'}}
					</view>
					<u-select v-model="showSel" mode="single-column" :list="item.options"
						@confirm="selConfirm($event,item.key)"></u-select>
				</template>
				<template v-else-if="item.type=='radio'">
					<u-radio-group v-model="tplForm[item.key]">
						<u-radio v-for="(item, index) in item.options" :key="index" :name="item.name">
							{{item.name}}
						</u-radio>
					</u-radio-group>
				</template>
				<template v-else-if="item.type=='checkbox'">
					<u-checkbox-group @change="checkGroupChange($event,item.key)">
						<u-checkbox v-model="item.checked" v-for="(item, index) in item.options" :key="index"
							:name="item.name">{{item.name}}</u-checkbox>
					</u-checkbox-group>
				</template>
				<template v-else-if="item.type=='cascader'">
					<!-- 小程序超过1024kb即会停止渲染;  未解决 -->
					<cascader :ref="`cascader_${item.key}`" :data="item.options" v-model="tplForm[item.key]" />
				</template>
				<template v-else-if="item.type=='upload'">
					<Upload :data="item.options" v-model="tplForm[item.key]" :tip="item.tip" />
				</template>
			</u-form-item>
		</u-form>
		<u-form ref="uForm" label-position="top" :error-type="['message','toast']" v-else>
			<u-form-item label="下单参数" :label-width="90">
				<u-input maxlength="100000" v-model="batchOrderContent" type="textarea" :placeholder="placeholder"
					:auto-height="false" :height="70" />
			</u-form-item>
		</u-form>
	</view>
</template>

<script>
	import Cascader from './cascader'
	import MixInput from './mix-input'
	import Upload from './upload'
	export default {
		components: {
			'cascader': Cascader,
			'mix-input': MixInput,
			'Upload': Upload,
		},
		props: {
			attach: {
				type: [Array, Boolean],
				default: () => []
			},
			showBatchOrder: {
				type: Number,
				default: 0
			},
		},
		data() {
			return {
				showSel: false,
				tplForm: {},
				tplRule: {},

				batchOrderContent: '',
			};
		},
		computed: {
			placeholder() {
				let arr = this.attach.map(item => item.name)
				return `${arr.join('###')}#-.-#下单数量  一行一个(下单数量不填默认下单1个)`
			},
		},
		watch: {
			attach: {
				handler(nv) {
					this.init(nv)
				},
				immediate: true
			},
			tplForm: {
				handler(nv) {
					this.$emit('attach-value', {
						batch_tpl: [nv]
					})
				},
				deep: true,
			},
			batchOrderContent: {
				handler(nv) {
					// console.log(nv);
					if (!nv) {
						this.$emit('attach-value', {
							batch_tpl: []
						})
						return
					}
					let rows = nv.split('\n')
					let batchOrderData = []
					for (let r of rows) {
						if (r) {




							// let coloms = r.split('###')
							// let tmp = {}
							// this.attach.forEach((item, idx) => {
							// 	tmp[item.key] = coloms[idx]
							// })
							// batchOrderData.push(tmp)

							let str = r.split('#-.-#')
							let strNum = 1
							let otherStr = str[0]
							if (str.length > 1) {

								strNum = str[str.length - 1]
								//去掉最后一个数组，合并其他数组
								otherStr = str.slice(0, -1).join('')
							}

							let coloms = otherStr.split('###')
							let tmp = {}
							this.attach.forEach((item, idx) => {
								tmp[item.key] = coloms[idx]
							})
							if (strNum) {
								tmp.kssquantity = strNum
							}
							batchOrderData.push(tmp)








						}
					}
					// this.batchOrderData = batchOrderData
					// console.log(batchOrderData)
					this.$emit('attach-value', {
						batch_tpl: batchOrderData
					})
				},
			},
		},
		created() {
			if (Object.keys(this.tplForm).length) {
				this.$emit('attach-value', {
					batch_tpl: [this.tplForm]
				})
			}
		},
		mounted() {

		},
		methods: {
			init(attach) {
				// 初始化表单的键,表单的验证规则
				if (!!attach) {
					let form = {}
					let rule = {}
					attach.forEach(item => {
						// 需要整理的数据,重新赋值
						// if (item.options && Object.prototype.toString.call(item.options) == '[object String]') {

						// }
						// 处理options
						if (item.type == 'text') {
							if (item.options)
								item.options = this.formatJson(item.options)
							else
								item.options = {}
						} else if (item.type == 'select') {
							if (item.options) {
								let arr = item.options.split(",")
								item.options = arr.map(i => {
									return {
										value: i,
										label: i
									}
								})
							}
						} else if (item.type == 'radio') {
							if (item.options) {
								let arr = item.options.split(",")
								item.options = arr.map(i => {
									return {
										name: i
									}
								})
							}

						} else if (item.type == 'checkbox') {
							if (item.options) {
								let arr = item.options.split(",")
								item.options = arr.map(i => {
									return {
										name: i,
										checked: false,
									}
								})
							}

						} else if (item.type == 'cascader') {
							if (item.options)
								item.options = this.formatJson(item.options)
							else
								item.options = []
						} else if (item.type == 'upload') {
							if (item.options)
								item.options = this.formatJson(item.options)
							else
								item.options = {}
						}

						// 初始化表单的值
						if (item.type == 'checkbox') {
							if (item.value) {
								item.options.map(op => {
									if (Array.isArray(item.value) && item.value.includes(op.name))
										op.checked = true
									return op
								})
								form[item.key] = item.value
							} else {
								form[item.key] = []
							}
						} else if (item.type == 'cascader') {
							form[item.key] = item.value ? item.value : {
								cascaderLabel: item.name,
								cascaderValues: [],
								cascaderTexts: [],
								formValues: [],
							}
						} else if (item.type == 'upload') {
							form[item.key] = item.value ? item.value : []
						} else {
							form[item.key] = item.value
						}

						// 初始化表单验证规则
						if (item.type == 'select') {
							rule[item.key] = [{
								required: true,
								message: `${item.name}未选择`,
								trigger: ['blur', 'change']
							}]
						} else if (item.type == 'radio') {
							rule[item.key] = [{
								required: true,
								message: `${item.name}未选择`,
								trigger: ['blur', 'change']
							}]
						} else if (item.type == 'checkbox') {
							rule[item.key] = [{
								validator: (rule, value, callback) => {
									return Array.isArray(value) && value.length ? true : false
								},
								message: `${item.name}未选择`,
								trigger: ['blur', 'change']
							}]
						} else if (item.type == 'cascader') {
							// 异步验证cascader组件的表单
							rule[item.key] = [{
								asyncValidator: (rule, value, callback) => {
									const ref = this.$refs[`cascader_${item.key}`][0]
									ref.doValid().then(() => {
										callback()
									})
								}
							}]
							// cascader组件走自己内部的表单验证
						} else if (item.type == 'upload') {
							rule[item.key] = [{
								validator: (rule, value, callback) => {
									return Array.isArray(value) && value.length ? true : false
								},
								message: `${item.name}未选择`,
								trigger: ['blur', 'change']
							}]
						} else {
							// 只要存在vali，就是必填
							if (item.vali) {
								if (item.vali == 'all') {
									rule[item.key] = [{
										required: true,
										message: `${item.name}不能为空`,
										trigger: ['blur', 'change']
									}]
								} else if (item.vali == 'number')
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											pattern: /^[0-9]*$/g,
											// 正则检验前先将值转为字符串
											transform(value) {
												return Number(value);
											},
											message: `${item.name}只能包含数字`
										}
									]
								else if (item.vali == 'qq') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											regexp: /^[1-9][0-9]{4,10}$/,
											message: `${item.name}的格式不正确`
										}
									]
								} else if (item.vali == 'mobile') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											regexp: /^1\d{10}$/,
											message: `${item.name}的格式不正确`,
											trigger: ['blur', 'change']
										}
									]
								} else if (item.vali == 'email') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											type: 'email',
											message: `${item.name}的格式不正确`,
											trigger: ['blur', 'change']
										}
									]
								} else if (item.vali == 'url') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`,
											trigger: ['blur', 'change']
										},
										{
											type: 'url',
											message: `${item.name}的格式不正确`,
											trigger: ['blur', 'change']
										}
									]
								} else if (item.vali == 'qqormobile') {
									rule[item.key] = [{
											required: true,
											message: `${item.name}不能为空`
										},
										{
											validator: (rule, value, callback) => {
												if (
													/^[1-9][0-9]{4,10}$/.test(value) === true ||
													/^1\d{10}$/.test(value) === true
												) {
													return true
												} else {
													return false
												}
											},
											message: `${item.name}的格式不正确`,
											trigger: ['blur', 'change']
										}
									]
								}
							}
						}
					})
					this.tplForm = Object.assign({}, form)
					this.tplRule = Object.assign({}, rule)
				} else {
					this.tplForm = {}
					this.tplRule = {}
				}
				if (Object.keys(this.tplRule).length) {
					this.$nextTick(() => {
						this.$refs.uForm.setRules(this.tplRule)
					})
				}
			},
			selConfirm(e, formkey) {
				this.tplForm[formkey] = e[0].value
			},
			checkGroupChange(e, formkey) {
				this.tplForm[formkey] = e
			},
			checkForm() {
				console.log(this.tplForm, this.tplRule)
				if (this.showBatchOrder) {
					return new Promise((resolve) => {
						resolve()
					})
				} else {
					if (Object.keys(this.tplForm).length) {
						return new Promise((resolve, reject) => {
							this.$refs.uForm.validate(valid => {
								if (valid) {
									resolve('验证通过')
								} else {
									reject('验证失败')
								}
							})
						})
					} else {
						return new Promise((resolve) => {
							resolve()
						})
					}
				}
			},
			formatJson(data) {
				if (typeof data == 'string' && data.constructor == String) {
					return JSON.parse(data)
				} else if (typeof data == 'object' && data.constructor == Object) {
					return data
				}
			},
		},
	};
</script>

<style scoped lang="scss" scoped>

</style>