// 封装函数到模块中

// 函数节流-封装
exports.throttle = (callback, delay) => {
	let pre = 0 // 默认值不要是Date.now() ==> 第1次事件立即调用
	return function(e) { // 节流函数/真正的事件回调函数   this是发生事件的标签
		const current = Date.now()
		if (current - pre > delay) { // 只有离上一次调用callback的时间差大于delay
			// 调用真正处理事件的函数, this是事件源, 参数是event
			callback.call(this, e)
			// 记录此次调用的时间
			pre = current
		}
	}
}

// 函数防抖-封装
exports.debounce = (callback, delay) => {
	return function(event) {
		// 如果上次事件还没有真正处理, 取消它
		// if (callback.timeoutId) { // 会查找原型链
		if (callback.hasOwnProperty('timeId')) { // 不会查找原型链
			// 清除
			clearTimeout(callback.timeId)
		}

		// 发事件发生指定事件后才调用处理事件的回调函数
		// 启动定时器, 只是准备真正处理
		callback.timeId = setTimeout(() => {
			// 正在处理事件
			callback.call(this, event)
			// 删除准备处理的标记
			delete callback.timeId
		}, delay)
	}
}

//通过js的内置对象JSON来进行数组对象的深拷贝
exports.deepClone = (obj) => {
	var _obj = JSON.stringify(obj),
		objClone = JSON.parse(_obj);
	return objClone;
}

// 生成随机字符
exports.randomString = (len) => {
	len = len || 32;
	var $chars = 'abcdefhijkmnprstwxyz2345678'; /****默认去掉了容易混淆的字符oOLl,9gq,Vv,Uu,I1****/
	var maxPos = $chars.length;
	var pwd = '';
	for (let i = 0; i < len; i++) {
		pwd += $chars.charAt(Math.floor(Math.random() * maxPos));
	}
	return pwd;
}

export const handleHtmlImg = (html) => {
	// 先手动清除所有img自带的样式，再手动添加max-width
	let newContent = html.replace(/<img[^>]*>/gi, function(match) {
		match = match.replace(/style="[^"]+"/gi, '').replace(/style='[^']+'/gi, '');
		match = match.replace(/width="[^"]+"/gi, '').replace(/width='[^']+'/gi, '');
		match = match.replace(/height="[^"]+"/gi, '').replace(/height='[^']+'/gi, '');
		return match;
	});
	newContent = newContent.replace(/style="[^"]+"/gi, function(match) {
		match = match.replace(/width:[^;]+;/gi, 'max-width:100%;').replace(/width:[^;]+;/gi,
			'max-width:100%;');
		return match;
	});
	newContent = newContent.replace(/<br[^>]*\/>/gi, '');
	newContent = newContent.replace(/<img/gi, '<img style="max-width:100%;"');
	return newContent;
}


export function mySetInterval(fn, delay) {
	setTimeout(() => {
		// console.log(new Date().toLocaleString()) // 可以打印时间看看
		fn()
		mySetInterval(fn, delay)
	}, delay)
}