<template>
	<view>
		<template v-if="numType == 1">
			<template v-if="isShow">
				<u-number-box v-model="quantityValue" :size="20" :min="startCount" :max="endCount"
					@change="quantityChange"></u-number-box>
			</template>
			<template v-else>
				<view @click="isShow=true">
					<text style="margin-right: 10rpx;">x{{quantity}}</text><u-icon name="arrow-right"
						color="#ccc"></u-icon>
				</view>
			</template>
		</template>
		<template v-else-if="numType == 2">
			<view @click="showNumPicker=true">
				<text style="margin-right: 10rpx;">x{{quantity}}</text>
				<u-icon name="arrow-right" color="#ccc"></u-icon>
			</view>
			<u-select v-model="showNumPicker" mode="single-column" :default-value="selectDefaultValue" :list="numList"
				@confirm="quantityChange" :safe-area-inset-bottom="true"></u-select>
		</template>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			quantity: {
				type: [Number, String],
				default: 0,
			},
			numType: {
				type: Number,
				default: 1,
			},
			startCount: {
				type: Number,
				default: 1,
			},
			endCount: {
				type: Number,
				default: 1,
			},
			numCount: {
				type: String,
				default: "",
			}
		},
		data() {
			return {
				isShow: false,
				quantityValue: 1,

				showNumPicker: false,
				numList: [],
			};
		},
		computed: {
			selectDefaultValue() {
				let index = this.numList.findIndex(item => item.value == this.quantityValue)
				if (index != -1)
					return [index]
				else
					return []
			}
		},
		watch: {
			quantity: {
				handler(nv) {
					this.quantityValue = nv - 0
				},
				immediate: true,
			}
		},
		created() {

		},
		mounted() {
			this.init()
		},
		methods: {
			init() {
				if (this.numType == 2) {
					this.numList = this.parseNumCount(this.numCount)
				}
			},
			quantityChange(e) {
				if (this.numType == 1) {
					this.$emit('quantity-change', e.value)
				} else if (this.numType == 2) {
					this.$emit('quantity-change', e[0].value)
				}
			},
			// 当num_type =2 时，使用select组件渲染下单数量，先解析下
			parseNumCount(str) {
				let arr = str.split(',')
				let re = []

				arr.forEach(item => {
					if (item.indexOf('-') != -1) {
						let tmp = item.split('-')
						for (let i = tmp[0]; i <= tmp[1]; i++) {
							re.push({
								value: Number(i),
								label: i
							})
						}
					} else {
						re.push({
							value: Number(item),
							label: item
						})
					}
				})
				return re
			},
		},
	};
</script>

