<template>
	<view>
		<u-upload :fileList="imgList" :action="postUrl" :header="header" :multiple="multiple" :limitType="limitType"
			:disabled="disabled" :maxCount="maxCount" :maxSize="maxSize" @on-success="handleUploadSuccess"
			:previewFullImage="true" uploadText="上传图片" width="120" height="120" @on-remove="handleRemove"
			:show-progress="true"></u-upload>
	</view>
</template>

<script>
	import config from "@/common/config"
	import {
		mapActions
	} from 'vuex'
	export default {
		props: {
			data: {
				type: Object,
				default: () => {
					return {}
				}
			},
			tip: {
				type: String,
				default: ''
			},
			value: {
				type: Array,
				default: () => []
			}
		},
		components: {

		},
		data() {
			return {
				imgList: []
			};
		},
		computed: {
			postUrl() {
				return config.apiurl + '/uni/upload'
			},
			header() {
				return {
					'authorization': 'Bearer ' + this.token,
					'sign': this.$util.reqSign(),
				}
			},
			multiple() {
				return this.data.multiple ? true : false
			},
			limitType() {
				let accept = this.data.accept
				return accept ? accept.split('\n').map(item => item.replace('.', '')) : ['png', 'jpg', 'jpeg',
					'webp', 'gif'
				]
			},
			disabled() {
				return this.data.disabled ? true : false
			},
			maxCount() {
				return this.data.limit || 1
			},
			maxSize() {
				let max_size = this.data.max_size
				max_size = parseInt(max_size)
				return max_size ? max_size * 1024 * 1024 : Number.MAX_VALUE
			},
		},
		watch: {},
		created() {

		},
		mounted() {
			this.imgList = this.value.map(item => {
				let obj = {}
				obj.url = item
				return obj
			})
		},
		methods: {
			...mapActions(['logout']),
			handleUploadSuccess(data, index, lists, name) {
				if (data.code) {
					if (data.code == 200) {
						this.$emit('input', lists.map((item) => {
							if ('response' in item) {
								return item.response.data.src
							} else {
								return item.url
							}
						}))
					} else if (data.code == 410000) {
						this.$util.msg(data.msg)
						setTimeout(async () => {
							await this.logout()
							this.$Router.push({
								path: '/pages/user/login',
								query: {
									redirect: this.$Route.fullPath
								}
							})
						}, 500)
					}

				} else {
					this.$util.msg('上传失败')
					return
				}
			},
			handleRemove(index, lists, name) {
				this.$emit('input', lists.map((item) => {
					return item.response
						.data.src
				}))
			},
		},
	};
</script>

