<template>
	<view style="padding: 0 20rpx;">
		<view class="goods-box">
			<template v-if="goodsList.length">
				<view class="goods-item" v-for="item,index in goodsList" :key="index">
					<view class="merchant">
						<view class="checker" :class="{'checker-on':checkSelected(1,item)}"
							@click="handelChecker(1,item)">
							<u-icon name="checkmark-circle"></u-icon>
						</view>
						<view class="merchant-name">
							<u-image width="40rpx" border-radius="10rpx" height="40rpx" :src="item.logo"></u-image>
							<text>{{item.name}}</text>
							<u-icon name="arrow-right" color="#B0B0B0" size="20"></u-icon>
						</view>
					</view>
					<view class="goods-list-box">
						<view class="goods-list-item" v-for="item2,index2 in item.list" :key="index2">
							<view class="checker" :class="{'checker-on':checkSelected(2,item2)}"
								@click="handelChecker(2,item2)">
								<u-icon name="checkmark-circle"></u-icon>
							</view>
							<view class="img">
								<template v-if="item2.goods.goods_type == 3 && item2.goods.spec_type == 1">
									<u-image width="150rpx" height="150rpx" border-radius="10rpx"
										:src="item2.attr.goods_img" @click="() => {
											$util.on(`/pages/goods/detail?id=${item2.goods_id}&spec_id=${item2.goods_sku_id}`)
										}"></u-image>
								</template>
								<template v-else>
									<u-image width="150rpx" height="150rpx" border-radius="10rpx"
										:src="item2.goods.goods_img" @click="() => {
										$util.on(`/pages/goods/detail?id=${item2.goods_id}&spec_id=${item2.goods_sku_id}`)
									}"></u-image>
								</template>
							</view>
							<view class="info">
								<view class="goods-name">
									<text class="name line2">{{item2.goods.goods_name}}</text>
								</view>
								<view class="spec" v-if="item2.goods.goods_type == 3 && item2.goods.spec_type == 1"
									@click="handelSpecClick(item2)">
									<text>{{item2.attr.suk}}</text>
									<u-icon name="arrow-right" color="#B0B0B0" size="20"></u-icon>
								</view>
								<view class="spec"
									v-else-if="item2.goods.goods_type == 1 || item2.goods.goods_type == 2"
									@click="handelAttachClick(item2)">
									<text>修改订单参数</text>
									<u-icon name="arrow-right" color="#B0B0B0" size="20"></u-icon>
								</view>
								<view class="tag">

								</view>
								<view class="price">
									<text>¥</text>
									<text
										v-if="item2.goods.goods_type == 3 && item2.goods.spec_type == 1">{{item2.attr.goods_price}}</text>
									<text v-else>{{item2.goods.goods_price}}</text>
								</view>
							</view>
							<view class="quantity">
								<slot name='quantity' :row="item2" :idx="index2" v-if="!isManage"></slot>
							</view>
						</view>
					</view>
				</view>
			</template>
			<template v-else>
				<view class="empty-cart">
					<u-empty mode="car"></u-empty>
				</view>
			</template>
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			goodsList: {
				type: Array,
				default: () => []
			},
			selectedIds: {
				type: Array,
				default: () => []
			},
			isManage: {
				type: Boolean,
				default: false,
			},
		},
		data() {
			return {
				form: {
					id: '', //购物车ID
					goods_id: '', //商品id
					goods_sku_id: '', //商品规格ID
					num: '', //商品数量
				},
				currSelectedIds: [], //选中状态,唯一id
			};
		},
		computed: {

		},
		watch: {
			selectedIds: {
				handler(nv) {
					this.currSelectedIds = this.$u.deepClone(nv)
				},
				immediate: true,
			},
		},
		created() {

		},
		mounted() {
			this.fetchData()
		},
		methods: {
			async fetchData() {

			},
			// checker被点击
			handelChecker(type, row) {
				let copy_ids = this.$u.deepClone(this.currSelectedIds)
				// 商户前面的checker被点击
				if (type == 1) {
					// 判断商户下的商品是否全部选中
					if (this.checkSelected(1, row)) {
						let unique_ids = row.list.map(item => item.id)
						unique_ids.map(curr_id => {
							let index = copy_ids.findIndex(id => id == curr_id)
							if (index != -1) {
								copy_ids.splice(index, 1)
							}
						})
					} else {
						let unique_ids = row.list.map(item => item.id)
						unique_ids.map(curr_id => {
							let index = copy_ids.findIndex(id => id == curr_id)
							if (index == -1) {
								copy_ids.push(curr_id)
							}
						})
					}
				}
				// 商品前面的checker点击
				else {
					let index = copy_ids.findIndex(id => id == row.id)
					if (index != -1) {
						copy_ids.splice(index, 1)
					} else {
						copy_ids.push(row.id)
					}
				}
				this.currSelectedIds = copy_ids
				this.$emit('selected-ids', {
					selectedIds: copy_ids,
					isSelectAll: this.checkAllSelected()
				})
			},
			// 判断是否已经选中
			checkSelected(type, row) {
				let copy_ids = this.$u.deepClone(this.currSelectedIds)
				let flag = false
				if (type == 1) {
					let unique_ids = row.list.map(item => item.id)
					let is_all = true
					unique_ids.map(curr_id => {
						let index = copy_ids.findIndex(id => id == curr_id)
						if (index == -1) {
							is_all = false
						}
					})
					flag = is_all ? true : false
				} else {
					let index = copy_ids.findIndex(id => id == row.id)
					if (index == -1) {
						flag = false
					} else {
						flag = true
					}
				}
				return flag
			},
			// 判断是否全部选中
			checkAllSelected() {
				let len = 0
				this.goodsList.map(item => {
					if (item.list && Array.isArray(item.list)) {
						len += item.list.length
					}
				})
				if (len == this.currSelectedIds.length)
					return true
				else
					return false
			},
			// 规格被点击
			handelSpecClick({
				id,
				goods_id,
				attr
			}) {
				this.$emit('spec-choose', {
					id,
					goods_id,
					spec_id: attr.id
				})
			},
			// 显示弹框修改下单模板
			handelAttachClick({
				id,
				goods_id
			}) {
				this.$emit('ordertpl-choose', {
					id,
					goods_id
				})
			},
			// 获取商品库存
			getStockNum(row, field) {
				return row.goods[field]
				// if(row.goods.goods_type == 3 && row.goods.spec_type == 1)
				// {
				// 	return row.attr[field]
				// }
				// else
				// {
				// 	return row.goods[field]
				// }
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.checker {
		color: #B0B0B0 !important;
	}

	.checker-on {
		color: #F05C02 !important;
	}

	.goods-box {
		display: flex;
		flex-direction: column;
		gap: 20rpx;

		.goods-item {
			display: flex;
			flex-direction: column;
			gap: 20rpx;
			background-color: #fff;
			border-radius: 10rpx;
			padding: 20rpx;

			.merchant {
				display: flex;
				gap: 20rpx;

				.merchant-name {
					display: flex;
					align-items: center;
					gap: 20rpx;
				}
			}

			.goods-list-box {
				display: flex;
				flex-direction: column;
				gap: 20rpx;

				.goods-list-item {
					display: flex;
					gap: 20rpx;
					align-items: center;

					.img {
						width: 150rpx;
					}

					.info {
						flex: 1;

						.goods-name {
							display: flex;
							gap: 20rpx;
							align-items: center;

							.name {
								flex: 1;
							}
						}

						.spec {
							color: #B0B0B0;
						}

						.tag {
							display: flex;
							gap: 10rpx;
							margin-top: 10rpx;

							&>text {
								border: 1px solid #F74B20;
								border-radius: 10rpx;
								font-size: 80%;
								color: #F74B20;
								padding: 1rpx 4rpx;
							}
						}

						.price {
							color: #FD5406;

							&>text:nth-child(1) {
								font-size: 20rpx;
								margin-right: 10rpx;
							}

							&>text:nth-child(2) {
								font-size: 40rpx;
								font-weight: bold;
							}
						}
					}

					.quantity {
						align-self: flex-start;
					}
				}
			}
		}

		.empty-cart {
			height: calc(100vh - 150px);
			display: flex;
			align-items: center;
			justify-content: center;
		}
	}
</style>