<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true"
			@close="close">
			<view class="popup-title">下单模板</view>
			<view class="popup-content">
				<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:'600rpx'}">
					<u-form :model="form" ref="uForm" label-position="top" :error-type="['message']">
						<u-form-item prop="batch_tpl" label="" label-width="0" :border-bottom="false">
							<Attach ref="attach" :attach="attach" :show-batch-order="showBatchOrder"
								@attach-value="getAttachValue" />
						</u-form-item>
						<u-form-item prop="mark" label="买家留言" :border-bottom="false">
							<u-input v-model="form.mark" type="textarea" :border="true" :height="150"
								:auto-height="true" />
						</u-form-item>
					</u-form>
				</scroll-view>
			</view>
			<view class="popup-footer">
				<u-button type="warning" shape="circle" @click="handelOk">确 定</u-button>
			</view>
		</u-popup>
	</view>
</template>

<script>
	import Attach from './attach'
	export default {
		components: {
			Attach
		},
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			}
		},
		data() {
			return {
				popupShow: false,

				// 单条购物车详情查询表单
				queryForm: {
					id: ''
				},
				attach: [], // 下单模板列表，包含模板值
				batchTpl: [], // 下单模板值

				showBatchOrder: 0, //显示批量下单

				form: {
					id: '', // 无用，组件回调返回父组件
					goods_id: '', // 无用，组件回调返回父组件
					batch_tpl: [], // 下单模板
					mark: '', // 订单备注
				},


			};
		},
		computed: {

		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			// id:购物车id，goods_id:商品id
			// 根据实际情况，可以新增showEdit2以达到目的
			showEdit({
				id,
				goods_id,
				attach
			}) {
				// 编辑
				if (id) {
					this.queryForm.id = id
					this.form.id = id
					this.form.goods_id = goods_id
					this.fetchData()
				}
				// 新增
				else {
					this.form.goods_id = goods_id
					this.attach = attach
				}

				this.popupShow = true
			},

			// 获取购物车详情
			async fetchData() {
				const data = await this.$u.api.goodsCartRead(this.queryForm)
				this.attach = data.info.goods.attach
				this.batchTpl = data.info.batch_tpl
			},
			close() {
				this.attach = this.$options.data().attach
				this.form = this.$options.data().form
			},
			handelOk() {
				this.$emit('ok', this.form)
				this.popupShow = false
			},
			// 返回商品模板的值
			getAttachValue({
				batch_tpl
			}) {
				this.form.batch_tpl = batch_tpl
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.popup-content {
		padding: 20rpx;

		.wrap {
			background-color: #f4f4f5;
			height: 300rpx;
			overflow-y: auto;
		}
	}

	.popup-footer {
		padding: 40rpx;
	}
</style>